    AwsEnvironmentConfig withDiscovery(String clusterLabel) {
        return new AwsEnvironmentConfig(awsConfig,
                                        amiId,
                                        instanceType,
                                        keyName,
                                        securityGroupIds,
                                        subnetId,
                                        userData,
                                        loadBalancer,
                                        some(clusterLabel),
                                        discoveryPollIntervalMs);
    }

